     1→/**
     2→ * Avi DM Service - Core integration service for Claude Code communication
     3→ * 
     4→ * This service provides the main interface between the Avi DM UI component
     5→ * and the Claude Code instance, handling HTTP requests, WebSocket connections,
     6→ * context management, and error handling.
     7→ */
     8→
     9→import {
    10→  ClaudeCodeConfig,
    11→  ClaudeRequest,
    12→  ClaudeResponse,
    13→  ConversationSession,
    14→  ConversationMessage,
    15→  ProjectContext,
    16→  FileContext,
    17→  GitContext,
    18→  ConnectionStatus,
    19→  ClaudeCodeError,
    20→  SendMessageOptions,
    21→  StreamingMessage,
    22→  SessionPreferences,
    23→  RequestOptions,
    24→  SystemStatus,
    25→  HealthCheckResponse
    26→} from '../types/claude-integration';
    27→
    28→import { HttpClient } from './HttpClient';
    29→import { WebSocketManager } from './WebSocketManager';
    30→import { ContextManager } from './ContextManager';
    31→import { SessionManager } from './SessionManager';
    32→import { ErrorHandler } from './ErrorHandler';
    33→import { SecurityManager } from './SecurityManager';
    34→
    35→/**
    36→ * Main service class for Claude Code integration
    37→ * 
    38→ * Provides high-level interface for:
    39→ * - Sending messages to Claude
    40→ * - Managing conversations and sessions
    41→ * - Handling project context
    42→ * - Real-time communication
    43→ * - Error handling and fallbacks
    44→ */
    45→export class AviDMService {
    46→  private config: ClaudeCodeConfig;
    47→  private httpClient: HttpClient;
    48→  private websocketManager: WebSocketManager;
    49→  private contextManager: ContextManager;
    50→  private sessionManager: SessionManager;
    51→  private errorHandler: ErrorHandler;
    52→  private securityManager: SecurityManager;
    53→  
    54→  private isInitialized: boolean = false;
    55→  private currentSessionId: string | null = null;
    56→  private connectionStatus: ConnectionStatus;
    57→  private eventListeners: Map<string, Set<Function>> = new Map();
    58→
    59→  constructor(config: Partial<ClaudeCodeConfig> = {}) {
    60→    this.config = this.mergeWithDefaults(config);
    61→    
    62→    // Initialize core components
    63→    this.httpClient = new HttpClient({
    64→      baseUrl: this.config.baseUrl,
    65→      timeout: this.config.timeout,
    66→      retryAttempts: this.config.retryAttempts
    67→    });
    68→    
    69→    this.websocketManager = new WebSocketManager({
    70→      url: this.config.websocketUrl,
    71→      reconnectAttempts: 5,
    72→      reconnectDelay: 2000,
    73→      heartbeatInterval: 30000,
    74→      messageQueueSize: 100
    75→    });
    76→    
    77→    this.contextManager = new ContextManager();
    78→    this.sessionManager = new SessionManager();
    79→    this.errorHandler = new ErrorHandler();
    80→    this.securityManager = new SecurityManager();
    81→    
    82→    this.connectionStatus = {
    83→      isConnected: false,
    84→      connectionQuality: 'offline',
    85→      reconnectAttempts: 0
    86→    };
    87→    
    88→    this.setupEventListeners();
    89→  }
    90→
    91→  // ============================================================================
    92→  // INITIALIZATION AND CONFIGURATION
    93→  // ============================================================================
    94→
    95→  private mergeWithDefaults(config: Partial<ClaudeCodeConfig>): ClaudeCodeConfig {
    96→    return {
    97→      baseUrl: config.baseUrl || 'http://localhost:3001', // SPARC FIX: Remove /api to avoid double /api/api prefix
    98→      timeout: config.timeout || 300000, // 5 minutes for Claude Code SDK variable performance (15-17s + buffer)
    99→      retryAttempts: config.retryAttempts || 3,
   100→      websocketUrl: config.websocketUrl || 'ws://localhost:3001/ws',
   101→      apiKey: config.apiKey,
   102→      rateLimits: {
   103→        messagesPerMinute: 30,
   104→        tokensPerHour: 50000,
   105→        ...config.rateLimits
   106→      },
   107→      security: {
   108→        enableAuth: false,
   109→        allowedOrigins: ['localhost:5173', 'localhost:3000'],
   110→        sanitizeContent: true,
   111→        ...config.security
   112→      },
   113→      fallback: {
   114→        enableOfflineMode: true,
   115→        cacheResponses: true,
   116→        maxCacheSize: 100,
   117→        ...config.fallback
   118→      }
   119→    };
   120→  }
   121→
   122→  private setupEventListeners(): void {
   123→    // WebSocket event handlers
   124→    this.websocketManager.onConnect(() => {
   125→      this.updateConnectionStatus({ isConnected: true, connectionQuality: 'excellent' });
   126→      this.emit('connected');
   127→    });
   128→    
   129→    this.websocketManager.onDisconnect((reason) => {
   130→      this.updateConnectionStatus({ 
   131→        isConnected: false, 
   132→        connectionQuality: 'offline',
   133→        error: reason 
   134→      });
   135→      this.emit('disconnected', { reason });
   136→    });
   137→    
   138→    this.websocketManager.onMessage((message: StreamingMessage) => {
   139→      this.handleStreamingMessage(message);
   140→    });
   141→    
   142→    this.websocketManager.onError((error) => {
   143→      const claudeError = this.errorHandler.handleError(error, {
   144→        operation: 'websocket_communication'
   145→      });
   146→      this.emit('error', claudeError);
   147→    });
   148→  }
   149→
   150→  /**
   151→   * Initialize the service and establish connections
   152→   */
   153→  async initialize(projectPath?: string): Promise<void> {
   154→    try {
   155→      // Check Claude Code health
   156→      const health = await this.healthCheck();
   157→      
   158→      if (health.status === 'down') {
   159→        throw new Error('Claude Code instance is not running');
   160→      }
   161→      
   162→      // Initialize context if project path provided
   163→      if (projectPath) {
   164→        await this.contextManager.initializeContext(projectPath);
   165→      }
   166→      
   167→      // Establish WebSocket connection
   168→      await this.websocketManager.connect(this.config.websocketUrl);
   169→      
   170→      this.isInitialized = true;
   171→      this.emit('initialized');
   172→      
   173→    } catch (error) {
   174→      const claudeError = this.errorHandler.handleError(error, {
   175→        operation: 'service_initialization',
   176→        projectPath
   177→      });
   178→      
   179→      if (this.config.fallback.enableOfflineMode) {
   180→        await this.errorHandler.enableOfflineMode();
   181→        this.isInitialized = true;
   182→        this.emit('initialized', { offlineMode: true });
   183→      } else {
   184→        throw claudeError;
   185→      }
   186→    }
   187→  }
   188→
   189→  // ============================================================================
   190→  // CORE MESSAGING API
   191→  // ============================================================================
   192→
   193→  /**
   194→   * Send a message to Claude Code
   195→   */
   196→  async sendMessage(
   197→    message: string, 
   198→    options: SendMessageOptions = {}
   199→  ): Promise<ClaudeResponse> {
   200→    if (!this.isInitialized) {
   201→      throw new Error('Service not initialized. Call initialize() first.');
   202→    }
   203→    
   204→    // Rate limiting check
   205→    if (this.currentSessionId) {
   206→      const canProceed = await this.securityManager.checkRateLimit(this.currentSessionId);
   207→      if (!canProceed) {
   208→        throw this.errorHandler.handleError(
   209→          new Error('Rate limit exceeded'),
   210→          { operation: 'send_message' }
   211→        );
   212→      }
   213→    }
   214→    
   215→    const requestId = this.generateRequestId();
   216→    
   217→    try {
   218→      // Prepare context
   219→      const context = await this.contextManager.serializeContext();
   220→      
   221→      // Build request
   222→      const request: ClaudeRequest = {
   223→        id: requestId,
   224→        message: this.securityManager.sanitizeContent(message),
   225→        context: JSON.parse(context),
   226→        sessionId: this.currentSessionId || '',
   227→        timestamp: new Date().toISOString(),
   228→        options: {
   229→          temperature: options.temperature,
   230→          maxTokens: options.maxTokens,
   231→          stream: options.stream || false,
   232→          systemPrompt: options.systemPrompt
   233→        }
   234→      };
   235→      
   236→      // Send request to the correct Claude Code SDK endpoint
   237→      console.log('🔧 AviDMService: Sending request to /api/claude-code/streaming-chat');
   238→      const response = await this.httpClient.post<ClaudeResponse>(
   239→        '/api/claude-code/streaming-chat',
   240→        {
   241→          message: request.message,
   242→          options: {
   243→            cwd: context.projectPath || '/workspaces/agent-feed',
   244→            enableTools: true,
   245→            ...request.options
   246→          }
   247→        }
   248→      );
   249→      
   250→      // Record request for rate limiting
   251→      if (this.currentSessionId) {
   252→        this.securityManager.recordRequest(this.currentSessionId);
   253→      }
   254→      
   255→      // Store message in session
   256→      if (this.currentSessionId && response.status === 'success') {
   257→        await this.sessionManager.addMessage(this.currentSessionId, {
   258→          id: this.generateMessageId(),
   259→          sessionId: this.currentSessionId,
   260→          role: 'user',
   261→          content: message,
   262→          timestamp: request.timestamp,
   263→          metadata: {
   264→            tokenCount: message.length // Rough estimate
   265→          }
   266→        });
   267→        
   268→        await this.sessionManager.addMessage(this.currentSessionId, {
   269→          id: response.id,
   270→          sessionId: this.currentSessionId,
   271→          role: 'assistant',
   272→          content: response.content,
   273→          timestamp: new Date().toISOString(),
   274→          metadata: response.metadata
   275→        });
   276→      }
   277→      
   278→      this.emit('messageReceived', response);
   279→      return response;
   280→      
   281→    } catch (error) {
   282→      const claudeError = this.errorHandler.handleError(error, {
   283→        operation: 'send_message',
   284→        requestId,
   285→        sessionId: this.currentSessionId
   286→      });
   287→      
   288→      // Try fallback response
   289→      if (this.config.fallback.enableOfflineMode) {
   290→        const fallbackResponse = await this.errorHandler.generateFallbackResponse(
   291→          message,
   292→          await this.contextManager.getProjectContext()
   293→        );
   294→        
   295→        return {
   296→          id: requestId,
   297→          requestId,
   298→          content: fallbackResponse.content,
   299→          metadata: {
   300→            model: 'fallback',
   301→            tokensUsed: 0,
   302→            processingTime: 0,
   303→            suggestions: fallbackResponse.suggestions
   304→          },
   305→          status: 'success'
   306→        };
   307→      }
   308→      
   309→      throw claudeError;
   310→    }
   311→  }
   312→
   313→  /**
   314→   * Send a streaming message to Claude Code
   315→   */
   316→  async sendMessageStream(
   317→    message: string,
   318→    onChunk: (chunk: string) => void,
   319→    options: SendMessageOptions = {}
   320→  ): Promise<void> {
   321→    if (!this.connectionStatus.isConnected) {
   322→      throw new Error('WebSocket connection required for streaming');
   323→    }
   324→    
   325→    const requestId = this.generateRequestId();
   326→    
   327→    // Set up chunk handler for this specific request
   328→    const handleChunk = (streamMessage: StreamingMessage) => {
   329→      if (streamMessage.requestId === requestId) {
   330→        switch (streamMessage.type) {
   331→          case 'chunk':
   332→            if (streamMessage.content) {
   333→              onChunk(streamMessage.content);
   334→            }
   335→            break;
   336→          case 'complete':
   337→            this.emit('streamComplete', requestId);
   338→            break;
   339→          case 'error':
   340→            this.emit('streamError', { requestId, error: streamMessage.error });
   341→            break;
   342→        }
   343→      }
   344→    };
   345→    
   346→    // Register temporary listener
   347→    this.on('streamingMessage', handleChunk);
   348→    
   349→    try {
   350→      // Prepare and send streaming request
   351→      const context = await this.contextManager.serializeContext();
   352→      
   353→      const request: ClaudeRequest = {
   354→        id: requestId,
   355→        message: this.securityManager.sanitizeContent(message),
   356→        context: JSON.parse(context),
   357→        sessionId: this.currentSessionId || '',
   358→        timestamp: new Date().toISOString(),
   359→        options: {
   360→          ...options,
   361→          stream: true
   362→        }
   363→      };
   364→      
   365→      this.websocketManager.send({
   366→        type: 'chat_request',
   367→        data: request
   368→      });
   369→      
   370→    } catch (error) {
   371→      this.off('streamingMessage', handleChunk);
   372→      throw this.errorHandler.handleError(error, {
   373→        operation: 'send_message_stream',
   374→        requestId
   375→      });
   376→    } finally {
   377→      // Clean up listener after a timeout
   378→      setTimeout(() => {
   379→        this.off('streamingMessage', handleChunk);
   380→      }, this.config.timeout);
   381→    }
   382→  }
   383→
   384→  // ============================================================================
   385→  // SESSION MANAGEMENT
   386→  // ============================================================================
   387→
   388→  /**
   389→   * Create a new conversation session
   390→   */
   391→  async createSession(
   392→    projectId: string,
   393→    projectPath?: string,
   394→    preferences?: Partial<SessionPreferences>
   395→  ): Promise<string> {
   396→    try {
   397→      let context: ProjectContext | undefined;
   398→      
   399→      if (projectPath) {
   400→        context = await this.contextManager.initializeContext(projectPath);
   401→      }
   402→      
   403→      const response = await this.httpClient.post<{ sessionId: string }>(
   404→        '/sessions',
   405→        { projectId, projectPath, context }
   406→      );
   407→      
   408→      const sessionId = response.sessionId;
   409→      this.currentSessionId = sessionId;
   410→      
   411→      // Initialize local session
   412→      const session: ConversationSession = {
   413→        id: sessionId,
   414→        projectId,
   415→        projectPath: projectPath || '',
   416→        startTime: new Date().toISOString(),
   417→        lastActivity: new Date().toISOString(),
   418→        messageCount: 0,
   419→        context: context || {} as ProjectContext,
   420→        preferences: {
   421→          autoSaveInterval: 30000,
   422→          maxHistoryMessages: 100,
   423→          contextSensitivity: 'medium',
   424→          includeGitContext: true,
   425→          includeFileTree: true,
   426→          preferredResponseStyle: 'detailed',
   427→          ...preferences
   428→        },
   429→        isActive: true
   430→      };
   431→      
   432→      await this.sessionManager.createSession(sessionId, session);
   433→      
   434→      this.emit('sessionStarted', { sessionId, projectId });
   435→      return sessionId;
   436→      
   437→    } catch (error) {
   438→      throw this.errorHandler.handleError(error, {
   439→        operation: 'create_session',
   440→        projectId,
   441→        projectPath
   442→      });
   443→    }
   444→  }
   445→
   446→  /**
   447→   * End the current session
   448→   */
   449→  async endSession(sessionId?: string): Promise<void> {
   450→    const targetSessionId = sessionId || this.currentSessionId;
   451→    
   452→    if (!targetSessionId) {
   453→      return;
   454→    }
   455→    
   456→    try {
   457→      // Save session before ending
   458→      await this.sessionManager.saveSession(targetSessionId);
   459→      
   460→      // Notify Claude Code
   461→      await this.httpClient.delete(`/sessions/${targetSessionId}`);
   462→      
   463→      // Clean up locally
   464→      await this.sessionManager.endSession(targetSessionId);
   465→      
   466→      if (targetSessionId === this.currentSessionId) {
   467→        this.currentSessionId = null;
   468→      }
   469→      
   470→      this.emit('sessionEnded', { sessionId: targetSessionId });
   471→      
   472→    } catch (error) {
   473→      this.errorHandler.handleError(error, {
   474→        operation: 'end_session',
   475→        sessionId: targetSessionId
   476→      });
   477→    }
   478→  }
   479→
   480→  /**
   481→   * Get conversation history for a session
   482→   */
   483→  async getConversationHistory(
   484→    sessionId?: string,
   485→    limit?: number
   486→  ): Promise<ConversationMessage[]> {
   487→    const targetSessionId = sessionId || this.currentSessionId;
   488→    
   489→    if (!targetSessionId) {
   490→      return [];
   491→    }
   492→    
   493→    try {
   494→      return await this.sessionManager.getMessages(targetSessionId, limit);
   495→    } catch (error) {
   496→      throw this.errorHandler.handleError(error, {
   497→        operation: 'get_conversation_history',
   498→        sessionId: targetSessionId
   499→      });
   500→    }
   501→  }
   502→
   503→  // ============================================================================
   504→  // CONTEXT MANAGEMENT
   505→  // ============================================================================
   506→
   507→  /**
   508→   * Update the project context
   509→   */
   510→  async updateProjectContext(context: Partial<ProjectContext>): Promise<void> {
   511→    try {
   512→      await this.contextManager.updateContext(context);
   513→      
   514→      if (this.currentSessionId && this.connectionStatus.isConnected) {
   515→        await this.httpClient.post('/context/update', {
   516→          sessionId: this.currentSessionId,
   517→          context: await this.contextManager.getProjectContext()
   518→        });
   519→      }
   520→      
   521→      this.emit('contextUpdated', context);
   522→      
   523→    } catch (error) {
   524→      throw this.errorHandler.handleError(error, {
   525→        operation: 'update_project_context'
   526→      });
   527→    }
   528→  }
   529→
   530→  /**
   531→   * Inject specific file contexts
   532→   */
   533→  async injectFileContext(files: FileContext[]): Promise<void> {
   534→    try {
   535→      const sanitizedFiles = files.map(file => ({
   536→        ...file,
   537→        content: this.securityManager.sanitizeContent(file.content)
   538→      }));
   539→      
   540→      if (this.currentSessionId && this.connectionStatus.isConnected) {
   541→        await this.httpClient.post('/context/files', {
   542→          sessionId: this.currentSessionId,
   543→          files: sanitizedFiles
   544→        });
   545→      }
   546→      
   547→      this.emit('fileContextInjected', sanitizedFiles);
   548→      
   549→    } catch (error) {
   550→      throw this.errorHandler.handleError(error, {
   551→        operation: 'inject_file_context'
   552→      });
   553→    }
   554→  }
   555→
   556→  /**
   557→   * Inject Git context information
   558→   */
   559→  async injectGitContext(gitInfo: GitContext): Promise<void> {
   560→    try {
   561→      await this.contextManager.updateGitContext(gitInfo);
   562→      
   563→      if (this.currentSessionId) {
   564→        await this.updateProjectContext({
   565→          currentBranch: gitInfo.currentBranch,
   566→          recentChanges: gitInfo.stagedChanges.concat(gitInfo.unstagedChanges)
   567→        });
   568→      }
   569→      
   570→      this.emit('gitContextInjected', gitInfo);
   571→      
   572→    } catch (error) {
   573→      throw this.errorHandler.handleError(error, {
   574→        operation: 'inject_git_context'
   575→      });
   576→    }
   577→  }
   578→
   579→  // ============================================================================
   580→  // CONNECTION MANAGEMENT
   581→  // ============================================================================
   582→
   583→  /**
   584→   * Check connection to Claude Code
   585→   */
   586→  async checkConnection(): Promise<ConnectionStatus> {
   587→    try {
   588→      const startTime = Date.now();
   589→      const health = await this.healthCheck();
   590→      const endTime = Date.now();
   591→      
   592→      const isHealthy = health.status === 'healthy';
   593→      const latency = endTime - startTime;
   594→      
   595→      this.updateConnectionStatus({
   596→        isConnected: isHealthy,
   597→        connectionQuality: this.getQualityFromLatency(latency),
   598→        latency,
   599→        reconnectAttempts: 0
   600→      });
   601→      
   602→      return this.connectionStatus;
   603→      
   604→    } catch (error) {
   605→      this.updateConnectionStatus({
   606→        isConnected: false,
   607→        connectionQuality: 'offline',
   608→        error: error instanceof Error ? error.message : 'Connection failed'
   609→      });
   610→      
   611→      return this.connectionStatus;
   612→    }
   613→  }
   614→
   615→  /**
   616→   * Attempt to reconnect to Claude Code
   617→   */
   618→  async reconnect(): Promise<void> {
   619→    try {
   620→      this.updateConnectionStatus({
   621→        ...this.connectionStatus,
   622→        reconnectAttempts: this.connectionStatus.reconnectAttempts + 1
   623→      });
   624→      
   625→      // Try HTTP connection first
   626→      await this.checkConnection();
   627→      
   628→      // If successful, try WebSocket reconnection
   629→      if (this.connectionStatus.isConnected) {
   630→        await this.websocketManager.connect(this.config.websocketUrl);
   631→      }
   632→      
   633→      this.emit('reconnected');
   634→      
   635→    } catch (error) {
   636→      throw this.errorHandler.handleError(error, {
   637→        operation: 'reconnect'
   638→      });
   639→    }
   640→  }
   641→
   642→  /**
   643→   * Health check for Claude Code instance
   644→   */
   645→  async healthCheck(): Promise<HealthCheckResponse> {
   646→    return await this.httpClient.get<HealthCheckResponse>('/health');
   647→  }
   648→
   649→  /**
   650→   * Get system status
   651→   */
   652→  async getSystemStatus(): Promise<SystemStatus> {
   653→    return await this.httpClient.get<SystemStatus>('/status');
   654→  }
   655→
   656→  // ============================================================================
   657→  // EVENT HANDLING
   658→  // ============================================================================
   659→
   660→  /**
   661→   * Register event listener
   662→   */
   663→  on(event: string, callback: Function): void {
   664→    if (!this.eventListeners.has(event)) {
   665→      this.eventListeners.set(event, new Set());
   666→    }
   667→    this.eventListeners.get(event)!.add(callback);
   668→  }
   669→
   670→  /**
   671→   * Remove event listener
   672→   */
   673→  off(event: string, callback: Function): void {
   674→    const listeners = this.eventListeners.get(event);
   675→    if (listeners) {
   676→      listeners.delete(callback);
   677→    }
   678→  }
   679→
   680→  /**
   681→   * Emit event to listeners
   682→   */
   683→  private emit(event: string, data?: any): void {
   684→    const listeners = this.eventListeners.get(event);
   685→    if (listeners) {
   686→      listeners.forEach(callback => {
   687→        try {
   688→          callback(data);
   689→        } catch (error) {
   690→          console.error(`Error in event listener for ${event}:`, error);
   691→        }
   692→      });
   693→    }
   694→  }
   695→
   696→  // ============================================================================
   697→  // PRIVATE HELPER METHODS
   698→  // ============================================================================
   699→
   700→  private handleStreamingMessage(message: StreamingMessage): void {
   701→    this.emit('streamingMessage', message);
   702→    
   703→    // Handle different message types
   704→    switch (message.type) {
   705→      case 'typing':
   706→        this.emit('typing', { sessionId: message.sessionId });
   707→        break;
   708→      case 'status':
   709→        this.emit('statusUpdate', message.content);
